'use client'

import { useState } from 'react'
import { createClient } from '@/lib/supabase/client'

export default function BriefForm({ clientId, token }: { clientId: string; token: string }) {
  const [step, setStep] = useState(1)
    const [submitted, setSubmitted] = useState(false)
      const [loading, setLoading] = useState(false)
        const [error, setError] = useState('')
          const [form, setForm] = useState({ project_type: '', description: '', budget_range: '', timeline: '', pages: '', has_branding: false, branding_notes: '', examples: '', additional_info: '' })
            function update(field: string, value: string | boolean) { setForm(prev => ({ ...prev, [field]: value })) }

              async function handleSubmit(e: React.FormEvent) {
                  e.preventDefault()
                      setLoading(true)
                          setError('')
                              const supabase = createClient()
                                  const { error: briefError } = await supabase.from('briefs').insert({ client_id: clientId, ...form })
                                      if (briefError) { setError(briefError.message); setLoading(false); return }
                                          await supabase.from('clients').update({ status: 'brief_submitted' }).eq('brief_token', token)
                                              setSubmitted(true)
                                                }

                                                  if (submitted) return (
                                                      <div className="bg-white rounded-2xl border border-gray-200 p-12 text-center">
                                                            <p className="text-5xl mb-4">🎉</p>
                                                                  <h2 className="text-2xl font-bold text-gray-900 mb-2">Brief submitted!</h2>
                                                                        <p className="text-gray-500">Your designer has been notified and will review your brief shortly.</p>
                                                                            </div>
                                                                              )

                                                                                return (
                                                                                    <form onSubmit={handleSubmit}>
                                                                                          <div className="flex items-center gap-2 mb-8">
                                                                                                  {[1,2,3].map(s => (
                                                                                                            <div key={s} className="flex items-center gap-2">
                                                                                                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${s <= step ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-500'}`}>{s < step ? '✓' : s}</div>
                                                                                                                                    {s < 3 && <div className={`h-0.5 w-16 ${s < step ? 'bg-indigo-600' : 'bg-gray-200'}`} />}
                                                                                                                                              </div>
                                                                                                                                                      ))}
                                                                                                                                                              <span className="ml-2 text-sm text-gray-500">{step === 1 ? 'The project' : step === 2 ? 'Design details' : 'Final notes'}</span>
                                                                                                                                                                    </div>

                                                                                                                                                                          <div className="bg-white rounded-2xl border border-gray-200 p-8">
                                                                                                                                                                                  {step === 1 && (
                                                                                                                                                                                            <div className="space-y-6">
                                                                                                                                                                                                        <div>
                                                                                                                                                                                                                      <label className="block text-sm font-semibold text-gray-900 mb-1.5">What type of project? <span className="text-red-500">*</span></label>
                                                                                                                                                                                                                                    <div className="grid grid-cols-2 gap-3">
                                                                                                                                                                                                                                                    {['Website','Landing page','E-commerce','Portfolio','Web app','Other'].map(type => (
                                                                                                                                                                                                                                                                      <button key={type} type="button" onClick={() => update('project_type', type)} className={`px-4 py-3 rounded-lg border text-sm font-medium text-left ${form.project_type === type ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300 text-gray-700'}`}>{type}</button>
                                                                                                                                                                                                                                                                                      ))}
                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                          <label className="block text-sm font-semibold text-gray-900 mb-1.5">Describe your project <span className="text-red-500">*</span></label>
                                                                                                                                                                                                                                                                                                                                                        <textarea required value={form.description} onChange={e => update('description', e.target.value)} rows={4} className="w-full px-4 py-3 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none" placeholder="What does your business do? What is the goal of this project?" />
                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                <div className="grid grid-cols-2 gap-4">
                                                                                                                                                                                                                                                                                                                                                                                              <div>
                                                                                                                                                                                                                                                                                                                                                                                                              <label className="block text-sm font-semibold text-gray-900 mb-1.5">Budget range</label>
                                                                                                                                                                                                                                                                                                                                                                                                                              <select value={form.budget_range} onChange={e => update('budget_range', e.target.value)} className="w-full px-4 py-2.5 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white">
                                                                                                                                                                                                                                                                                                                                                                                                                                                <option value="">Select range...</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <option>Under $1,000</option><option>$1,000 – $3,000</option><option>$3,000 – $5,000</option><option>$5,000 – $10,000</option><option>$10,000+</option><option>Not sure yet</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </select>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <label className="block text-sm font-semibold text-gray-900 mb-1.5">Ideal timeline</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <select value={form.timeline} onChange={e => update('timeline', e.target.value)} className="w-full px-4 py-2.5 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-white">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <option value="">Select timeline...</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <option>ASAP</option><option>1–2 weeks</option><option>2–4 weeks</option><option>1–2 months</option><option>2–3 months</option><option>Flexible</option>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </select>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {step === 2 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="space-y-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <label className="block text-sm font-semibold text-gray-900 mb-1.5">What pages or sections do you need?</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <textarea value={form.pages} onChange={e => update('pages', e.target.value)} rows={3} className="w-full px-4 py-3 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none" placeholder="Homepage, About, Services, Portfolio, Contact..." />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <label className="block text-sm font-semibold text-gray-900 mb-2">Do you have existing branding?</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex gap-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {[{ label: 'Yes, I have a logo and brand colours', value: true }, { label: 'No, starting from scratch', value: false }].map(opt => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button key={String(opt.value)} type="button" onClick={() => update('has_branding', opt.value)} className={`flex-1 px-4 py-3 rounded-lg border text-sm font-medium ${form.has_branding === opt.value ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-200 hover:border-gray-300 text-gray-700'}`}>{opt.label}</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {form.has_branding && <textarea value={form.branding_notes} onChange={e => update('branding_notes', e.target.value)} rows={2} className="w-full mt-3 px-4 py-3 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none" placeholder="Describe your brand colours, fonts, style..." />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <label className="block text-sm font-semibold text-gray-900 mb-1.5">Examples or inspiration</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <textarea value={form.examples} onChange={e => update('examples', e.target.value)} rows={3} className="w-full px-4 py-3 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none" placeholder="stripe.com, linear.app — I like clean, minimal designs..." />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {step === 3 && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="space-y-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <label className="block text-sm font-semibold text-gray-900 mb-1.5">Anything else your designer should know?</label>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <textarea value={form.additional_info} onChange={e => update('additional_info', e.target.value)} rows={5} className="w-full px-4 py-3 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 resize-none" placeholder="Special requirements, integrations, target audience..." />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="text-sm text-indigo-800 font-medium mb-1">Ready to submit?</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="text-sm text-indigo-700">Your designer will review this and get back to you with a proposal.</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {error && <div className="mt-4 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg text-sm">{error}</div>}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex justify-between mt-8">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {step > 1 ? <button type="button" onClick={() => setStep(s => s - 1)} className="px-6 py-2.5 border border-gray-300 text-gray-700 rounded-lg text-sm font-medium hover:bg-gray-50">Back</button> : <div />}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {step < 3 ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button type="button" onClick={() => { if (step === 1 && (!form.project_type || !form.description)) { setError('Please select a project type and describe your project.'); return } setError(''); setStep(s => s + 1) }} className="px-6 py-2.5 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700">Continue →</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button type="submit" disabled={loading} className="px-8 py-2.5 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 disabled:opacity-50">{loading ? 'Submitting...' : 'Submit brief'}</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </form>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }